function solve(n: number, edges: number[][]): number {
    const graph: Map<number, [number, number, number][]> = new Map();
    for (const [u, v, start, end] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u)!.push([v, start, end]);
    }

    const heap: [number, number][] = [[0, 0]]; // [current_time, current_node]
    const visited: Map<number, number> = new Map();

    while (heap.length > 0) {
        const [currentTime, node] = heap.shift()!;
        if (node === n - 1) {
            return currentTime;
        }
        if (visited.has(node) && visited.get(node)! <= currentTime) {
            continue;
        }
        visited.set(node, currentTime);

        // Option to stay (wait for 1 time unit)
        heap.push([currentTime + 1, node]);
        heap.sort((a, b) => a[0] - b[0]);

        // Option to move via edges
        const neighbors = graph.get(node) || [];
        for (const [neighbor, start, end] of neighbors) {
            if (currentTime > end) {
                continue;
            }
            // The earliest time we can take this edge is max(currentTime, start)
            const t = Math.max(currentTime, start);
            if (t <= end) {
                heap.push([t + 1, neighbor]);
                heap.sort((a, b) => a[0] - b[0]);
            }
        }
    }

    return -1;
}
